// src/content-generators.ts// 콘텐츠 생성 관련 함수들// import { stripHtml } from './utils.js';// import { QualityMetrics } from './types';// import { resolveOfficialLink } from './cta/resolve';// 임시로 stripHtml 함수 정의function stripHtml(html: string): string {  return html.replace(/<[^>]*>/g, '');}// 임시로 resolveOfficialLink mockfunction resolveOfficialLink(input: any): any {  return {    name: input.query,    url: `https://example.com/${input.query.toLowerCase().replace(/\s+/g, '-')}`  };}import fs from 'fs';import path from 'path';// 성능 최적화: 정규식 캐시const regexCache = new Map<string, RegExp>();function getCachedRegex(pattern: string, flags: string = 'i'): RegExp {  const key = `${pattern}_${flags}`;  if (!regexCache.has(key)) {    regexCache.set(key, new RegExp(pattern, flags));  }  return regexCache.get(key)!;}// 성능 최적화: 문자열 유사도 계산 캐시const similarityCache = new Map<string, number>();// CTA 효과성 추적을 위한 데이터 저장소let ctaEffectivenessData: {  [key: string]: {    impressions: number;    clicks: number;    lastUpdated: string;    topics: string[];  }} = {};const CTA_DATA_FILE = path.resolve(process.cwd(), 'data/cta-effectiveness.json');/** * CTA 효과성 데이터 로드 */function loadCTAEffectivenessData(): void {  try {    if (fs.existsSync(CTA_DATA_FILE)) {      const data = fs.readFileSync(CTA_DATA_FILE, 'utf-8');      ctaEffectivenessData = JSON.parse(data);    }  } catch (e) {    console.warn('CTA 효과성 데이터 로드 실패:', e);    ctaEffectivenessData = {};  }}/** * CTA 효과성 데이터 저장 */function saveCTAEffectivenessData(): void {  try {    const dir = path.dirname(CTA_DATA_FILE);    if (!fs.existsSync(dir)) {      fs.mkdirSync(dir, { recursive: true });    }    fs.writeFileSync(CTA_DATA_FILE, JSON.stringify(ctaEffectivenessData, null, 2));  } catch (e) {    console.warn('CTA 효과성 데이터 저장 실패:', e);  }}/** * CTA 효과성 기록 (임프레션) */export function trackCTAImpression(query: string, topics: string[]): void {  if (!ctaEffectivenessData[query]) {    ctaEffectivenessData[query] = {      impressions: 0,      clicks: 0,      lastUpdated: new Date().toISOString(),      topics: topics    };  }  ctaEffectivenessData[query].impressions++;  ctaEffectivenessData[query].lastUpdated = new Date().toISOString();  saveCTAEffectivenessData();}/** * CTA 클릭률 계산 */function getCTAClickRate(query: string): number {  const data = ctaEffectivenessData[query];  if (!data || data.impressions === 0) return 0;  return data.clicks / data.impressions;}/** * 고급 CTA 우선순위 알고리즘 */function calculateAdvancedPriority(rec: any, index: number, allRecs: any[], analysis: any): number {  let finalPriority = rec.priority;  // 1. 효과성 기반 점수 (40% 가중치)  const clickRate = getCTAClickRate(rec.query);  const effectivenessScore = clickRate * 40; // 0-40점  finalPriority += effectivenessScore;  // 2. 다양성 점수 (20% 가중치) - 중복 카테고리 피하기  const categoryDiversity = calculateCategoryDiversity(rec, allRecs);  finalPriority += categoryDiversity * 20; // 0-20점  // 3. 콘텐츠 적합성 점수 (25% 가중치)  const contentRelevance = calculateContentRelevance(rec, analysis);  finalPriority += contentRelevance * 25; // 0-25점  // 4. 최근성 점수 (15% 가중치)  const recencyScore = calculateRecencyScore(rec.query);  finalPriority += recencyScore * 15; // 0-15점  return Math.round(finalPriority);}/** * 카테고리 다양성 계산 (중복 카테고리 피하기) */function calculateCategoryDiversity(rec: any, allRecs: any[]): number {  const categories = {    shopping: ['쿠팡', '네이버 쇼핑', '무신사', '지그재그', '롯데백화점', '다나와'],    booking: ['야놀자', '여기어때', 'CGV', '메가박스', '예스24 티켓', '인터파크 티켓'],    food: ['배달의민족', '쿠팡이츠', '요기요'],    finance: ['카카오뱅크', '토스', '네이버페이', '직방', '다방'],    education: ['인프런', '패스트캠퍼스', 'EBS', '야나두']  };  let diversityScore = 1.0; // 기본 점수  for (const [category, sites] of Object.entries(categories)) {    const categorySites = sites.filter(site => rec.query.includes(site));    if (categorySites.length > 0) {      // 같은 카테고리의 다른 사이트가 이미 선택되었는지 확인      const sameCategoryCount = allRecs.filter(otherRec =>        otherRec !== rec && sites.some(site => otherRec.query.includes(site))      ).length;      // 같은 카테고리가 많을수록 다양성 점수 감소      diversityScore *= Math.max(0.3, 1.0 - (sameCategoryCount * 0.2));    }  }  return diversityScore;}/** * 콘텐츠 적합성 계산 */function calculateContentRelevance(rec: any, analysis: any): number {  const { mainTopic, subTopics, keywords } = analysis;  let relevanceScore = 0;  // 주제 매칭 점수  const topicMappings: { [key: string]: string[] } = {    '크리스마스': ['선물', '쇼핑', '음식', '여행'],    '여행': ['항공', '숙박', '렌터카', '투어'],    '쇼핑': ['쿠팡', '네이버', '가격비교', '배송'],    '음식': ['배달', '맛집', '레시피', '외식'],    '건강': ['병원', '약', '다이어트', '피트니스'],    '금융': ['은행', '투자', '대출', '보험'],    '교육': ['강의', '자격증', '언어', '프로그래밍']  };  const relevantTerms = topicMappings[mainTopic] || [];  const isRelevant = relevantTerms.some(term => rec.query.toLowerCase().includes(term));  if (isRelevant) relevanceScore += 0.8;  // 소제목 매칭 점수  const subTopicMatch = subTopics.some((sub: string) =>    rec.query.toLowerCase().includes(sub.toLowerCase()) ||    sub.toLowerCase().includes(rec.query.toLowerCase())  );  if (subTopicMatch) relevanceScore += 0.2;  return Math.min(1.0, relevanceScore);}/** * 최근성 점수 계산 (최근에 효과적이었던 CTA 우선) */function calculateRecencyScore(query: string): number {  const data = ctaEffectivenessData[query];  if (!data) return 0;  const lastUpdated = new Date(data.lastUpdated);  const now = new Date();  const daysSinceUpdate = (now.getTime() - lastUpdated.getTime()) / (1000 * 60 * 60 * 24);  // 최근 30일 이내 업데이트된 CTA는 보너스 점수  if (daysSinceUpdate <= 30) {    return Math.max(0, 1.0 - (daysSinceUpdate / 30));  }  return 0;}/** * 고급 우선순위 알고리즘 적용 */function applyAdvancedPriorityAlgorithm(recommendations: any[], analysis: any): any[] {  return recommendations.map((rec, index, allRecs) => ({    ...rec,    priority: calculateAdvancedPriority(rec, index, allRecs, analysis)  }));}// 초기 데이터 로드loadCTAEffectivenessData();function calculateStringSimilarity(str1: string, str2: string): number {  const cacheKey = `${str1}|${str2}`;  if (similarityCache.has(cacheKey)) {    return similarityCache.get(cacheKey)!;  }    const similarity = getEditDistance(str1, str2) / Math.max(str1.length, str2.length);  similarityCache.set(cacheKey, similarity);  return similarity;}function getEditDistance(str1: string, str2: string): number {  const matrix: number[][] = [];    for (let i = 0; i <= str2.length; i++) {    matrix[i] = [i];  }    for (let j = 0; j <= str1.length; j++) {    const row = matrix[0];    if (row) {      row[j] = j;    }  }    for (let i = 1; i <= str2.length; i++) {    const row = matrix[i];    if (!row) continue;    for (let j = 1; j <= str1.length; j++) {      const prevRow = matrix[i - 1];      if (!prevRow) continue;      const prevCol = prevRow[j - 1];      const currCol = row[j - 1];      const prevRowCol = prevRow[j];            if (str2.charAt(i - 1) === str1.charAt(j - 1)) {        row[j] = prevCol ?? 0;      } else {        row[j] = Math.min(          (prevCol ?? 0) + 1,          (currCol ?? 0) + 1,          (prevRowCol ?? 0) + 1        );      }    }  }    const finalRow = matrix[str2.length];  return finalRow?.[str1.length] ?? 0;}// ---------- 중복 소제목 제거 시스템 ----------export function removeDuplicateHeadings(content: string): string {  if (!content) return content;    try {    const lines = content.split('\n');    const seen = new Set<string>();    const filteredLines: string[] = [];        for (const line of lines) {      // h2, h3 태그 감지 (성능 최적화: 정규식 캐시 사용)      const h2Regex = getCachedRegex('<h2[^>]*>(.*?)</h2>');      const h3Regex = getCachedRegex('<h3[^>]*>(.*?)</h3>');      const h2Match = line.match(h2Regex);      const h3Match = line.match(h3Regex);            if (h2Match || h3Match) {        const headingText = stripHtml(h2Match?.[1] || h3Match?.[1] || '').toLowerCase().trim();                if (!headingText || headingText.length < 2) {          filteredLines.push(line);          continue;        }                // 유사한 제목 검사 (80% 이상 유사하면 중복으로 간주)        let isDuplicate = false;        for (const seenHeading of seen) {          const similarity = calculateStringSimilarity(headingText, seenHeading);          if (similarity > 0.8) {            isDuplicate = true;            break;          }        }                if (!isDuplicate) {          seen.add(headingText);          filteredLines.push(line);        }        // 중복이면 해당 라인은 제외      } else {        filteredLines.push(line);      }    }        return filteredLines.join('\n');  } catch (e) {    console.warn('중복 소제목 제거 중 오류:', e);    return content;  }}// ---------- 품질 검증 시스템 ----------/*export function validateContentQuality(html: string, topic: string, existingSections?: string[]): QualityMetrics {  // 함수 내용 생략 - 테스트용으로 주석 처리    return {      readabilityScore: 70,      valueScore: 70,      originalityScore: 70,      expertiseScore: 70,      uniquenessScore: 70,      independenceScore: 70,      overallScore: 70,    issues: ['테스트용으로 주석 처리됨']    };  }*/// 새로운 고유성 검사 함수function checkContentUniqueness(text: string): number {  try {    const sentences = splitKoreanSentences(text);    let penalty = 0;        // 문장 유사성 검사    const sentenceMap = new Map<string, number>();    for (const sentence of sentences) {      const normalized = sentence.replace(/\d+/g, 'N').replace(/[^\w\s가-힣]/g, '').toLowerCase();      const count = sentenceMap.get(normalized) || 0;      sentenceMap.set(normalized, count + 1);      if (count > 0) {        penalty += 10; // 중복 문장마다 10점 감점      }    }        // 패턴 반복 검사    const patterns = [      /(?:이는|이것은).{10,30}(?:때문입니다|것입니다)/g,      /(?:따라서|그러므로|그래서).{10,30}(?:합니다|습니다)/g,      /(?:예를 들어|예시로).{10,30}(?:있습니다|됩니다)/g    ];        for (const pattern of patterns) {      const matches = text.match(pattern) || [];      if (matches.length > 2) {        penalty += (matches.length - 2) * 5; // 2개 초과시 5점씩 감점      }    }        return Math.min(penalty, 50); // 최대 50점까지 감점  } catch (e) {    return 0;  }}// 새로운 섹션 독립성 검사 함수function checkSectionIndependence(currentText: string, existingSections: string[]): number {  try {    let penalty = 0;    const currentTokens = new Set(tokenizeForSimilarity(currentText));        for (const existingSection of existingSections) {      const existingTokens = new Set(tokenizeForSimilarity(existingSection));      const similarity = calculateJaccardSimilarity(currentTokens, existingTokens);            if (similarity > 0.4) { // 40% 이상 유사하면 감점        penalty += (similarity - 0.4) * 100; // 40% 초과분만큼 감점      }    }        return Math.min(penalty, 40); // 최대 40점까지 감점  } catch (e) {    return 0;  }}function tokenizeForSimilarity(text: string): string[] {  try {    return stripHtml(text)      .toLowerCase()      .replace(/\d+/g, 'NUM')  // 숫자를 통일      .replace(/[^\w\s가-힣]/g, ' ')      .split(/\s+/)      .filter(token => token.length >= 2)      .slice(0, 100); // 처리 속도를 위해 처음 100개만  } catch (e) {    return [];  }}function calculateJaccardSimilarity(setA: Set<string>, setB: Set<string>): number {  try {    const intersection = new Set([...setA].filter(x => setB.has(x)));    const union = new Set([...setA, ...setB]);    return union.size === 0 ? 0 : intersection.size / union.size;  } catch (e) {    return 0;  }}function countExpertTerms(text: string, topic: string): number {  try {    const lowerText = text.toLowerCase();    const lowerTopic = topic.toLowerCase();        // 주제별 전문 용어 정의    const expertTerms: { [key: string]: string[] } = {      '렌터카': ['보험', '면책', '차량', '예약', '반납', '운전자', '렌트비', '보증금', '할인', '쿠폰'],      '여행': ['관광', '숙박', '교통', '예약', '일정', '비자', '환율', '관광지', '투어', '가이드'],      '건강': ['의료', '치료', '진료', '예방', '건강검진', '약물', '복용', '증상', '진단', '처방'],      '투자': ['포트폴리오', '수익률', '리스크', '자산', '투자', '주식', '채권', '펀드', '분석', '전략'],      '프로그래밍': ['코드', '알고리즘', '데이터베이스', 'API', '프레임워크', '라이브러리', '함수', '클래스', '변수', '배포'],      '요리': ['재료', '조리법', '양념', '레시피', '맛', '영양', '칼로리', '조리시간', '온도', '도구']    };        // 주제에 맞는 전문 용어 찾기    let matchedTerms: string[] = [];    for (const [key, terms] of Object.entries(expertTerms)) {      if (lowerTopic.includes(key)) {        matchedTerms = terms;        break;      }    }        // 일반적인 전문 용어도 추가    if (matchedTerms.length === 0) {      matchedTerms = ['방법', '전략', '기법', '절차', '과정', '원리', '특징', '장점', '단점', '효과'];    }        // 전문 용어 개수 세기    let count = 0;    for (const term of matchedTerms) {      if (lowerText.includes(term)) {        count++;      }    }        return count;  } catch (e) {    return 0;  }}function splitKoreanSentences(text: string): string[] {  try {    return text      .split(/[.!?。！？]\s*/)      .map(s => s.trim())      .filter(s => s.length > 10);  } catch (e) {    return [text];  }}// ---------- 콘텐츠 정리 함수들 ----------export function removeBoilerplateContent(html: string): string {  try {    let cleaned = html;        // 일반적인 보일러플레이트 패턴 제거    const boilerplatePatterns = [      /<p[^>]*>\s*(?:이 글은|본 글은|이번 글은|오늘은|이번에는).{10,50}(?:에 대해|에 관한|에 대한).{10,100}(?:알아보겠습니다|소개하겠습니다|설명하겠습니다|다루겠습니다)\.?\s*<\/p>/gi,      /<p[^>]*>\s*(?:그럼|그렇다면|이제|자, 그럼|그러면).{10,50}(?:시작해보겠습니다|알아보겠습니다|살펴보겠습니다|진행하겠습니다)\.?\s*<\/p>/gi,      /<p[^>]*>\s*(?:마지막으로|마무리로|결론적으로|요약하면|정리하면).{10,100}(?:이상입니다|끝입니다|마치겠습니다|입니다)\.?\s*<\/p>/gi,      // 중간 마무리 문구 제거 (강화)      /<p[^>]*>\s*(?:지금까지|이번 섹션에서는|여기까지).{10,80}(?:알아보았습니다|살펴보았습니다|확인했습니다)\.?\s*<\/p>/gi,      /<p[^>]*>\s*(?:이제|자|그럼) (?:마지막|다음) (?:섹션|내용|부분).{10,80}(?:알아보겠습니다|살펴보겠습니다|확인해보겠습니다)\.?\s*<\/p>/gi,      /<p[^>]*>\s*(?:오늘 배운|지금까지 다룬|여기서 다룬).{10,60}(?:정리|요약|마무리).{10,60}\.?\s*<\/p>/gi    ];        for (const pattern of boilerplatePatterns) {      cleaned = cleaned.replace(pattern, '');    }        // 연속된 빈 단락 제거    cleaned = cleaned.replace(/(<p[^>]*>\s*<\/p>\s*){3,}/gi, '<p></p><p></p>');        // 불필요한 공백 정리    cleaned = cleaned.replace(/\s+/g, ' ').trim();        return cleaned;  } catch (e) {    console.warn('보일러플레이트 제거 중 오류:', e);    return html;  }}export function removeConsecutiveDuplicates(html: string): string {  try {    const lines = html.split('\n');    const cleanedLines: string[] = [];    let lastLine = '';        for (const line of lines) {      cons